using System.Collections;
using System.Collections.Generic;
using UnityEngine;

// ─── Acções NPC — Snapshots do Status do Player ────────────────────────────
//
// Permitem que NPCs "guardem" e "restaurem" partes do estado do player.
// Útil para mecânicas de "roubar e devolver":
//   - NPC confisca sementes, corações, animais, etc. ao entrar numa área.
//   - Mais tarde (noutra cena, outro NPC), o estado é restaurado exactamente
//     como estava.
//
// Os snapshots são runtime-only (não persistidos no save file). Se o jogo for
// fechado entre o Save e o Restore, o snapshot perde-se — design para
// situações dentro da mesma sessão de jogo ou guardar manualmente via
// SaveManager antes de viajar entre cenas.
//
// Fluxo típico:
//   [Evento NPC "Chefe Sela Animais"]
//     1. Action_SavePlayerSnapshot  — key="sela_floresta", ticks para o que guardar
//     2. Action_LockAllFormsExceptStart  — bloqueia roda visualmente
//     3. [outros passos: remover sementes, diálogo, ...]
//
//   [Evento NPC "Chefe Devolve Tudo" — mesma ou outra área]
//     4. Action_RestorePlayerSnapshot — key="sela_floresta"
//     5. Action_ClearFormLocks        — garante que a roda fica limpa
//     6. Action_DiscardPlayerSnapshot — key="sela_floresta"  (opcional, limpeza)

/// <summary>
/// Tira um snapshot do estado actual do player e guarda com a chave indicada.
/// Apenas os campos com o tick activado são capturados; o resto é ignorado.
/// </summary>
[System.Serializable]
public class Action_SavePlayerSnapshot : NpcAction
{
    [Tooltip("Chave única para identificar este snapshot. Use nomes descritivos (ex: \"sela_floresta\", \"roubo_bruxa\"). Snapshots com a mesma chave sobrepõem-se.")]
    public string snapshotKey = "snapshot";

    [Header("O que guardar")]
    [Tooltip("Guarda o número actual de Sementes.")] public bool saveSementes = true;
    [Tooltip("Guarda as Runas de Gaia disponíveis.")] public bool saveRunasDeGaia = false;
    [Tooltip("Guarda os Ecos Perdidos disponíveis.")] public bool saveEcosPerdidos = false;
    [Tooltip("Guarda os Brotos de Vida em stock.")] public bool saveBrotosDeVida = false;
    [Tooltip("Guarda os corações actuais (vida actual).")] public bool saveCurrentHearts = true;
    [Tooltip("Guarda o número máximo de corações (recipientes).")] public bool saveMaxHearts = false;
    [Tooltip("Guarda todo o inventário de itens (lista completa com quantidades).")] public bool saveInventory = false;
    [Tooltip("Guarda o ID do item equipado.")] public bool saveEquippedItem = false;
    [Tooltip("Guarda a lista de animais desbloqueados (freedAnimalIds).")] public bool saveFreedAnimals = false;
    [Tooltip("Guarda os bloqueios temporários de formas activos no FormSwitcher (para restaurar quais formas estavam cinzentas).")] public bool saveLockedForms = true;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) yield break;

        var snapshot = new PlayerSnapshot();

        if (saveSementes)        { snapshot.hasSementes = true;      snapshot.sementes = progress.sementes; }
        if (saveRunasDeGaia)     { snapshot.hasRunasDeGaia = true;   snapshot.runasDeGaia = progress.runasDeGaia; }
        if (saveEcosPerdidos)    { snapshot.hasEcosPerdidos = true;  snapshot.ecosPerdidos = progress.ecosPerdidos; }
        if (saveBrotosDeVida)    { snapshot.hasBrotosDeVida = true;  snapshot.brotosDeVida = progress.brotosDeVida; }
        if (saveCurrentHearts)   { snapshot.hasCurrentHearts = true; snapshot.currentHearts = progress.currentHearts; }
        if (saveMaxHearts)       { snapshot.hasMaxHearts = true;     snapshot.maxHearts = progress.maxHearts; }

        if (saveInventory)
        {
            snapshot.hasInventory = true;
            snapshot.inventory = new List<InventoryEntry>();
            foreach (var entry in progress.inventory)
                snapshot.inventory.Add(new InventoryEntry { itemId = entry.itemId, quantity = entry.quantity });
        }

        if (saveEquippedItem)
        {
            snapshot.hasEquippedItem = true;
            snapshot.equippedItemId = progress.equippedItemId;
        }

        if (saveFreedAnimals)
        {
            snapshot.hasFreedAnimals = true;
            snapshot.freedAnimalIds = new List<string>(progress.freedAnimalIds);
        }

        if (saveLockedForms)
        {
            var switcher = SnapshotUtil.GetSwitcher();
            if (switcher != null)
            {
                snapshot.hasLockedForms = true;
                snapshot.lockedFormIds = switcher.CaptureLockedFormIds();
            }
        }

        progress.StoreSnapshot(snapshotKey, snapshot);
    }
}

/// <summary>
/// Restaura o estado do player a partir do snapshot com a chave indicada.
/// Apenas os campos que foram capturados (flags "has*") são restaurados.
/// O snapshot NÃO é removido automaticamente — use Action_DiscardPlayerSnapshot
/// para limpar depois de restaurar (ou deixe para ser substituído na próxima
/// vez que Action_SavePlayerSnapshot for chamado com a mesma chave).
/// </summary>
[System.Serializable]
public class Action_RestorePlayerSnapshot : NpcAction
{
    [Tooltip("Chave do snapshot a restaurar (deve corresponder à chave usada em Action_SavePlayerSnapshot).")]
    public string snapshotKey = "snapshot";

    [Tooltip("Se activado, remove o snapshot da memória depois de restaurar (evita restaurar acidentalmente duas vezes).")]
    public bool discardAfterRestore = false;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) yield break;

        if (!progress.TryGetSnapshot(snapshotKey, out PlayerSnapshot snapshot))
        {
            Debug.LogWarning($"[Action_RestorePlayerSnapshot] Snapshot \"{snapshotKey}\" não encontrado.");
            yield break;
        }

        if (snapshot.hasSementes)
        {
            int delta = snapshot.sementes - progress.sementes;
            progress.GiveSementes(delta);
        }

        if (snapshot.hasRunasDeGaia)
        {
            int delta = snapshot.runasDeGaia - progress.runasDeGaia;
            progress.GiveRunasDeGaia(delta);
        }

        if (snapshot.hasEcosPerdidos)
        {
            int delta = snapshot.ecosPerdidos - progress.ecosPerdidos;
            progress.GiveEcosPerdidos(delta);
        }

        if (snapshot.hasBrotosDeVida)
        {
            int delta = snapshot.brotosDeVida - progress.brotosDeVida;
            progress.GiveBrotosDeVida(delta);
        }

        if (snapshot.hasMaxHearts)
        {
            // maxHearts não tem setter directo; ajusta via SetMaxHearts se existir,
            // ou directamente (PlayerProgress.maxHearts é public).
            progress.maxHearts = Mathf.Clamp(snapshot.maxHearts, 1, PlayerProgress.MaxHeartsCap);
        }

        if (snapshot.hasCurrentHearts)
        {
            // Aplica após maxHearts (que pode ter sido restaurado acima).
            progress.currentHearts = Mathf.Clamp(snapshot.currentHearts, 0, progress.maxHearts);
            progress.NotifyHealthChanged();
        }

        if (snapshot.hasInventory && snapshot.inventory != null)
        {
            progress.RestoreInventoryFromSnapshot(snapshot.inventory);
        }

        if (snapshot.hasEquippedItem)
        {
            progress.equippedItemId = snapshot.equippedItemId;
        }

        if (snapshot.hasFreedAnimals && snapshot.freedAnimalIds != null)
        {
            progress.RestoreFreedAnimalsFromSnapshot(snapshot.freedAnimalIds);

            // Task 6.3: usar ReplaceUnlockedForms para sincronizar o FormSwitcher,
            // garantindo que formas libertadas DEPOIS do snapshot também são removidas.
            // O loop anterior com UnlockForm() apenas adicionava formas mas nunca removia.
            var switcher = SnapshotUtil.GetSwitcher();
            if (switcher != null)
            {
                var db = GameDatabase.Instance;
                var formsToRestore = new System.Collections.Generic.List<AnimalFormData>();
                if (db != null)
                {
                    foreach (var id in progress.freedAnimalIds)
                    {
                        var form = db.FindAnimalForm(id);
                        if (form != null) formsToRestore.Add(form);
                    }
                }
                switcher.ReplaceUnlockedForms(formsToRestore);
            }
        }

        if (snapshot.hasLockedForms)
        {
            var switcher = SnapshotUtil.GetSwitcher();
            if (switcher != null)
                switcher.RestoreLockedFormIds(snapshot.lockedFormIds);
        }

        if (discardAfterRestore)
            progress.DiscardSnapshot(snapshotKey);
    }
}

/// <summary>
/// Remove um snapshot da memória sem restaurar — útil para limpar snapshots
/// após restauração ou quando o evento "roubo" foi cancelado.
/// </summary>
[System.Serializable]
public class Action_DiscardPlayerSnapshot : NpcAction
{
    [Tooltip("Chave do snapshot a remover.")]
    public string snapshotKey = "snapshot";

    public override IEnumerator Execute(NpcController npc)
    {
        PlayerProgress.Instance?.DiscardSnapshot(snapshotKey);
        yield break;
    }
}

// ─── Utilitário interno ────────────────────────────────────────────────────

internal static class SnapshotUtil
{
    internal static FormSwitcher GetSwitcher()
    {
        var playerT = PlayerLocator.Find();
        if (playerT == null) return null;
        return playerT.GetComponent<FormSwitcher>()
            ?? playerT.GetComponentInChildren<FormSwitcher>();
    }
}
